            let activeDayData = null;

            function getTypeColor(type) { if (type === 'world') return 'var(--accent-world)'; if (type === 'major') return 'var(--accent-major)'; if (type === 'user') return 'var(--accent-user)'; if (type === 'character') return 'var(--accent-char)'; return '#ccc'; }
            function translateType(type) { if (type === 'world') return 'Thế giới'; if (type === 'major') return 'Sự kiện lớn'; if (type === 'user') return 'Cá nhân'; if (type === 'character') return 'Ràng buộc NPC'; return 'Khác'; }
            function setStatus(text, isError = false) { if (!footerStatus) return; footerStatus.textContent = text; footerStatus.style.color = isError ? '#f87171' : 'var(--accent-char)'; }

            function formatEventPrompt(ev) {
                const dateLabel = `${ev.dateStr}${ev.dayName ? ` ${ev.dayName}` : ''}`.trim();
                const npcLabel = ev.npcAction && ev.npcAction.trim() !== '' ? `\n> Động thái NPC lúc này: ${ev.npcAction}` : '';
                return `- Vào lúc [${ev.time}, ${dateLabel}] tại [${ev.location}]: Tiến hành sự kiện ${translateType(ev.type)} mang tên "${ev.title}".\n> Nội dung chính: ${ev.description}${npcLabel}`;
            }
            function buildInputText(events) {
                if (!events || events.length === 0) return '';
                if (events.length === 1) {
                    const ev = events[0];
                    const dateLabel = `${ev.dateStr}${ev.dayName ? ` ${ev.dayName}` : ''}`.trim();
                    const npcLabel = ev.npcAction && ev.npcAction.trim() !== '' ? `\n[Tài liệu ẩn: Động thái NPC trong bóng tối: ${ev.npcAction}]` : '';
                    return `[Chỉ thị Tối cao]: Hãy đẩy dòng thời gian đến [${ev.time}, ${dateLabel}], tại [${ev.location}]. Khởi chạy sự kiện: "${ev.title}".\nNội dung trọng tâm: ${ev.description}${npcLabel}`;
                }
                return `[Chỉ thị Tối cao]: Hãy đẩy dòng thời gian cốt truyện để chạy liên tiếp chuỗi sự kiện sau đây một cách logic và tự nhiên nhất:\n\n${events.map((ev, index) => formatEventPrompt(ev)).join('\n\n')}`;
            }

            function getSelectedEvents() { return Array.from(selectedEventIds).map(id => eventLookup.get(id)).filter(Boolean).sort((a, b) => a.dayIndex - b.dayIndex || a.eventIndex - b.eventIndex); }
            function updateSelectionUI() {
                const count = selectedEventIds.size;
                if (selectionCount) selectionCount.textContent = String(count);
